import React from 'react';
import {reduxForm} from 'redux-form'
import {maxLengthCreator, required} from "../../utils/validators/validators";
import {Area, createField} from "../Common/FormsControls/FormsControls";
import {connect} from "react-redux";
import {login} from "../../redux/auth-reducer";
import Redirect from "react-router-dom/es/Redirect";
import styles from '../Common/FormsControls/FormsControls.module.css'


const maxLength30 = maxLengthCreator(30);
const Input = Area('input')

const LoginForm =({handleSubmit, error, captchaUrl}) => {
     return <form onSubmit={handleSubmit}>
         {createField('Input', 'Email', "email", "text", [required, maxLength30])}
         {createField('Input', 'Password', "password", "password", [required, maxLength30])}
         {createField('Input', null, "rememberMe", "checkbox", null, 'remember me')}
         {captchaUrl && <img src={captchaUrl}/>}
         {captchaUrl && createField('Input', 'Symbols from image', 'captcha', "text", [required])}

                        {error && <div className={styles.formSummeryError}>
                    {error}
                </div>}
                <button>
                    Login
                </button>

        </form>
};

const LoginReduxForm = reduxForm ({
    form: 'login'
}) (LoginForm);

const Login =(props) => {
    const onSubmit = (formData) => {
    props.login (formData.email, formData.password, formData.rememberMe, formData.captcha)
    }
    if (props.isAuth) {
        return <Redirect to={'/profile'}/>
    }
    return <div>
        <h1>LOGIN</h1>
        <LoginReduxForm onSubmit={onSubmit} captchaUrl={props.captchaUrl}/>
                </div>
}

const mapStateToProps = (state) => ({
    isAuth: state.auth.isAuth,
    captchaUrl: state.auth.captchaUrl
})

export default connect (mapStateToProps, {login}) (Login);

